    def calculate_performance_metrics(self, hist, current_price):
        """Calculate historical performance over different periods"""
        try:
            metrics = {}
            
            if hist.empty or len(hist) < 50:
                return None
            
            close_prices = hist['Close'].dropna()
            
            if len(close_prices) < 50:
                return None
            
            if len(close_prices) >= 480:
                price_2y_ago = close_prices.iloc[0]
                if price_2y_ago > 0:
                    metrics['return_2y'] = ((current_price - price_2y_ago) / price_2y_ago) * 100
                else:
                    metrics['return_2y'] = 0
            else:
                metrics['return_2y'] = 0
            
            if len(close_prices) >= 252:
                price_1y_ago = close_prices.iloc[-252]
                if price_1y_ago > 0:
                    metrics['return_1y'] = ((current_price - price_1y_ago) / price_1y_ago) * 100
                else:
                    metrics['return_1y'] = 0
            else:
                metrics['return_1y'] = 0
            
            if len(close_prices) >= 126:
                price_6m_ago = close_prices.iloc[-126]
                if price_6m_ago > 0:
                    metrics['return_6m'] = ((current_price - price_6m_ago) / price_6m_ago) * 100
                else:
                    metrics['return_6m'] = 0
            else:
                metrics['return_6m'] = 0
            
            if len(close_prices) >= 63:
                price_3m_ago = close_prices.iloc[-63]
                if price_3m_ago > 0:
                    metrics['return_3m'] = ((current_price - price_3m_ago) / price_3m_ago) * 100
                else:
                    metrics['return_3m'] = 0
            else:
                metrics['return_3m'] = 0
            
            if len(close_prices) >= 21:
                price_1m_ago = close_prices.iloc[-21]
                if price_1m_ago > 0:
                    metrics['return_1m'] = ((current_price - price_1m_ago) / price_1m_ago) * 100
                else:
                    metrics['return_1m'] = 0
            else:
                metrics['return_1m'] = 0
            
            if len(close_prices) >= 252:
                years = len(close_prices) / 252
                start_price = close_prices.iloc[0]
                if start_price > 0 and years > 0:
                    metrics['cagr'] = (((current_price / start_price) ** (1/years)) - 1) * 100
                else:
                    metrics['cagr'] = 0
            else:
                metrics['cagr'] = 0
            
            daily_returns = close_prices.pct_change().dropna()
            if len(daily_returns) > 0:
                std_dev = daily_returns.std()
                if pd.notna(std_dev):
                    metrics['volatility'] = float(std_dev * np.sqrt(252) * 100)
                else:
                    metrics['volatility'] = 0
            else:
                metrics['volatility'] = 0
            
            risk_free_rate = 6.0
            if metrics['volatility'] > 0:
                metrics['sharpe_ratio'] = (metrics['cagr'] - risk_free_rate) / metrics['volatility']
            else:
                metrics['sharpe_ratio'] = 0
            
            if len(daily_returns) > 0:
                cumulative = (1 + daily_returns).cumprod()
                running_max = cumulative.expanding().max()
                drawdown = (cumulative - running_max) / running_max
                max_dd = drawdown.min()
                if pd.notna(max_dd):
                    metrics['max_drawdown'] = float(max_dd * 100)
                else:
                    metrics['max_drawdown'] = -10
            else:
                metrics['max_drawdown'] = -10
            
            if len(daily_returns) > 0:
                metrics['win_rate'] = float((daily_returns > 0).sum() / len(daily_returns) * 100)
            else:
                metrics['win_rate'] = 50
            
            if len(daily_returns) > 0:
                gains = daily_returns[daily_returns > 0]
                losses = daily_returns[daily_returns < 0]
                if len(gains) > 0 and len(losses) > 0:
                    avg_gain = gains.mean() * 100
                    avg_loss = abs(losses.mean() * 100)
                    if avg_loss > 0:
                        metrics['gain_loss_ratio'] = avg_gain / avg_loss
                    else:
                        metrics['gain_loss_ratio'] = 1
                else:
                    metrics['gain_loss_ratio'] = 1
            else:
                metrics['gain_loss_ratio'] = 1
            
            for key in metrics:
                if pd.isna(metrics[key]) or np.isinf(metrics[key]):
                    metrics[key] = 0
            
            return metrics
        except Exception as e:
            return None
    
    def calculate_technical_indicators(self, hist):
        """Calculate comprehensive technical indicators"""
        try:
            close = hist['Close'].dropna()
            high = hist['High'].dropna()
            low = hist['Low'].dropna()
            volume = hist['Volume'].dropna()
            
            if len(close) < 50:
                return None
            
            indicators = {}
            
            indicators['sma_20'] = float(close.rolling(window=20).mean().iloc[-1])
            indicators['sma_50'] = float(close.rolling(window=50).mean().iloc[-1])
            
            if len(close) >= 100:
                indicators['sma_100'] = float(close.rolling(window=100).mean().iloc[-1])
            else:
                indicators['sma_100'] = indicators['sma_50']
            
            if len(close) >= 200:
                indicators['sma_200'] = float(close.rolling(window=200).mean().iloc[-1])
            else:
                indicators['sma_200'] = indicators['sma_100']
            
            indicators['ema_12'] = float(close.ewm(span=12, adjust=False).mean().iloc[-1])
            indicators['ema_26'] = float(close.ewm(span=26, adjust=False).mean().iloc[-1])
            
            delta = close.diff()
            gain = (delta.where(delta > 0, 0)).rolling(window=14).mean()
            loss = (-delta.where(delta < 0, 0)).rolling(window=14).mean()
            rs = gain / loss
            rsi = 100 - (100 / (1 + rs))
            rsi_val = rsi.iloc[-1]
            if pd.notna(rsi_val) and not np.isinf(rsi_val):
                indicators['rsi'] = float(max(0, min(100, rsi_val)))
            else:
                indicators['rsi'] = 50
            
            macd_line = indicators['ema_12'] - indicators['ema_26']
            signal_line = close.ewm(span=9, adjust=False).mean().iloc[-1]
            indicators['macd'] = float(macd_line)
            indicators['macd_signal'] = float(signal_line)
            indicators['macd_histogram'] = indicators['macd'] - indicators['macd_signal']
            
            if len(high) >= 28 and len(low) >= 28:
                plus_dm = high.diff()
                minus_dm = -low.diff()
                plus_dm[plus_dm < 0] = 0
                minus_dm[minus_dm < 0] = 0
                
                tr1 = high - low
                tr2 = abs(high - close.shift())
                tr3 = abs(low - close.shift())
                tr = pd.concat([tr1, tr2, tr3], axis=1).max(axis=1)
                atr = tr.rolling(window=14).mean()
                
                plus_di = 100 * (plus_dm.rolling(window=14).mean() / atr)
                minus_di = 100 * (minus_dm.rolling(window=14).mean() / atr)
                dx = 100 * abs(plus_di - minus_di) / (plus_di + minus_di + 0.0001)
                adx = dx.rolling(window=14).mean()
                adx_val = adx.iloc[-1]
                if pd.notna(adx_val) and not np.isinf(adx_val):
                    indicators['adx'] = float(max(0, min(100, adx_val)))
                else:
                    indicators['adx'] = 25
            else:
                indicators['adx'] = 25
            
            sma_20 = close.rolling(window=20).mean()
            std_20 = close.rolling(window=20).std()
            indicators['bb_upper'] = float((sma_20 + (std_20 * 2)).iloc[-1])
            indicators['bb_middle'] = float(sma_20.iloc[-1])
            indicators['bb_lower'] = float((sma_20 - (std_20 * 2)).iloc[-1])
            if indicators['bb_middle'] > 0:
                indicators['bb_width'] = float(((indicators['bb_upper'] - indicators['bb_lower']) / indicators['bb_middle']) * 100)
            else:
                indicators['bb_width'] = 10
            
            indicators['volume_sma_20'] = float(volume.rolling(window=20).mean().iloc[-1])
            if indicators['volume_sma_20'] > 0:
                recent_vol = volume.iloc[-5:].mean()
                indicators['volume_ratio'] = float(recent_vol / indicators['volume_sma_20'])
            else:
                indicators['volume_ratio'] = 1.0
            
            if len(low) >= 252:
                indicators['support_52w'] = float(low.iloc[-252:].min())
            else:
                indicators['support_52w'] = float(low.min())
            
            if len(high) >= 252:
                indicators['resistance_52w'] = float(high.iloc[-252:].max())
            else:
                indicators['resistance_52w'] = float(high.max())
            
            for key in indicators:
                if pd.isna(indicators[key]) or np.isinf(indicators[key]):
                    if 'ratio' in key:
                        indicators[key] = 1.0
                    elif 'rsi' in key:
                        indicators[key] = 50.0
                    else:
                        indicators[key] = 0.0
            
            return indicators
        except Exception as e:
            return None
    
    def calculate_quality_score(self, stock_data, performance, indicators):
        """Calculate comprehensive quality score (0-100)"""
        try:
            score = 0
            signals = []
            
            current_price = stock_data['current_price']
            
            perf_score = 0
            
            if performance['return_2y'] > 100:
                perf_score += 10
                signals.append("Exceptional 2Y growth >100%")
            elif performance['return_2y'] > 50:
                perf_score += 8
                signals.append("Strong 2Y growth >50%")
            elif performance['return_2y'] > 20:
                perf_score += 6
                signals.append("Good 2Y growth >20%")
            elif performance['return_2y'] > 0:
                perf_score += 4
            
            if performance['return_1y'] > 50:
                perf_score += 10
                signals.append("Excellent 1Y return >50%")
            elif performance['return_1y'] > 30:
                perf_score += 8
                signals.append("Strong 1Y return >30%")
            elif performance['return_1y'] > 15:
                perf_score += 6
            elif performance['return_1y'] > 0:
                perf_score += 4
            
            if performance['return_3m'] > 15 and performance['return_1m'] > 5:
                perf_score += 10
                signals.append("Strong recent momentum")
            elif performance['return_3m'] > 10:
                perf_score += 6
            elif performance['return_3m'] > 0:
                perf_score += 3
            
            if performance['cagr'] > 25:
                perf_score += 10
                signals.append(f"Outstanding CAGR {performance['cagr']:.1f}%")
            elif performance['cagr'] > 15:
                perf_score += 7
            elif performance['cagr'] > 10:
                perf_score += 5
            
            score += perf_score
            
            tech_score = 0
            
            if current_price > indicators['sma_20'] > indicators['sma_50'] > indicators['sma_200']:
                tech_score += 10
                signals.append("Strong uptrend - All MAs aligned")
            elif current_price > indicators['sma_50'] > indicators['sma_200']:
                tech_score += 7
                signals.append("Uptrend - Price above key MAs")
            elif current_price > indicators['sma_200']:
                tech_score += 5
            
            if 40 < indicators['rsi'] < 70:
                tech_score += 5
                signals.append("Healthy RSI - Room to grow")
            elif 30 < indicators['rsi'] < 40:
                tech_score += 4
                signals.append("Oversold - Reversal opportunity")
            elif indicators['rsi'] < 30:
                tech_score += 3
            
            if indicators['macd'] > indicators['macd_signal'] and indicators['macd_histogram'] > 0:
                tech_score += 5
                signals.append("Bullish MACD crossover")
            elif indicators['macd'] > indicators['macd_signal']:
                tech_score += 3
            
            if indicators['adx'] > 25:
                tech_score += 5
                signals.append(f"Strong trend (ADX {indicators['adx']:.0f})")
            elif indicators['adx'] > 20:
                tech_score += 3
            
            if indicators['volume_ratio'] > 1.5:
                tech_score += 5
                signals.append("Volume surge detected")
            elif indicators['volume_ratio'] > 1.2:
                tech_score += 3
            
            score += tech_score
            
            risk_score = 0
            
            if performance['sharpe_ratio'] > 1.5:
                risk_score += 10
                signals.append("Excellent risk-adjusted returns")
            elif performance['sharpe_ratio'] > 1.0:
                risk_score += 7
            elif performance['sharpe_ratio'] > 0.5:
                risk_score += 5
            
            if performance['max_drawdown'] > -20:
                risk_score += 5
                signals.append("Low drawdown - Stable stock")
            elif performance['max_drawdown'] > -30:
                risk_score += 3
            
            if performance['win_rate'] > 55:
                risk_score += 5
            elif performance['win_rate'] > 52:
                risk_score += 3
            
            score += risk_score
            
            consistency_score = 0
            
            positive_periods = sum([
                performance['return_2y'] > 0,
                performance['return_1y'] > 0,
                performance['return_6m'] > 0,
                performance['return_3m'] > 0
            ])
            
            if positive_periods == 4:
                consistency_score += 10
                signals.append("Consistent growth across all periods")
            elif positive_periods == 3:
                consistency_score += 7
            elif positive_periods >= 2:
                consistency_score += 4
            
            score += consistency_score
            
            final_score = min(score, 100)
            
            if final_score >= 80:
                rating = "EXCELLENT"
                confidence = 90 + (final_score - 80) / 2
            elif final_score >= 70:
                rating = "VERY GOOD"
                confidence = 80 + (final_score - 70)
            elif final_score >= 60:
                rating = "GOOD"
                confidence = 70 + (final_score - 60)
            elif final_score >= 50:
                rating = "MODERATE"
                confidence = 60 + (final_score - 50)
            else:
                rating = "FAIR"
                confidence = 50 + (final_score / 2)
            
            return {
                'quality_score': int(final_score),
                'rating': rating,
                'confidence': round(confidence, 1),
                'signals': signals[:8],
                'performance_contribution': perf_score,
                'technical_contribution': tech_score,
                'risk_contribution': risk_score,
                'consistency_contribution': consistency_score
            }
        except Exception as e:
            return None
    
    def analyze_all_stocks(self):
        if not self.stock_data:
            print("⚠️  No stock data available for analysis.")
            self.top_20_stocks = []
            return
        
        print(f"Performing deep analysis on {len(self.stock_data)} stocks...")
        print("Calculating: Performance metrics, Technical indicators, Quality scores")
        print("=" * 80 + "\n")
        
        analysis_count = 0
        
        for symbol, data in self.stock_data.items():
            try:
                hist = data['history']
                current_price = data['current_price']
                
                performance = self.calculate_performance_metrics(hist, current_price)
                if performance is None:
                    continue
                
                indicators = self.calculate_technical_indicators(hist)
                if indicators is None:
                    continue
                
                quality = self.calculate_quality_score(data, performance, indicators)
                if quality is None:
                    continue
                
                target_30d = current_price * (1 + max(performance['return_1m'], 3) / 100 * 1.5)
                target_90d = current_price * (1 + max(performance['return_3m'], 8) / 100 * 1.2)
                stop_loss = max(indicators['support_52w'] * 1.02, current_price * 0.92)
                
                potential_gain_30d = ((target_30d - current_price) / current_price) * 100
                potential_gain_90d = ((target_90d - current_price) / current_price) * 100
                
                self.analyzed_stocks.append({
                    'symbol': symbol,
                    'name': data['name'],
                    'sector': data['sector'],
                    'industry': data['industry'],
                    'current_price': current_price,
                    'market_cap': data['market_cap'],
                    'history': hist,
                    'performance': performance,
                    'indicators': indicators,
                    'quality': quality,
                    'target_30d': float(target_30d),
                    'target_90d': float(target_90d),
                    'stop_loss': float(stop_loss),
                    'potential_gain_30d': float(potential_gain_30d),
                    'potential_gain_90d': float(potential_gain_90d)
                })
                
                analysis_count += 1
                if analysis_count % 10 == 0:
                    print(f"Analyzed {analysis_count}/{len(self.stock_data)} stocks...")
                
            except Exception as e:
                continue
        
        if not self.analyzed_stocks:
            print("\n⚠️  Failed to analyze any stocks.")
            self.top_20_stocks = []
            return
        
        self.analyzed_stocks.sort(key=lambda x: x['quality']['quality_score'], reverse=True)
        
        print(f"\n{'='*80}")
        print(f"ANALYSIS COMPLETE")
        print(f"{'='*80}")
        print(f"Total stocks analyzed: {len(self.analyzed_stocks)}")
        
        excellent = len([s for s in self.analyzed_stocks if s['quality']['rating'] == 'EXCELLENT'])
        very_good = len([s for s in self.analyzed_stocks if s['quality']['rating'] == 'VERY GOOD'])
        good = len([s for s in self.analyzed_stocks if s['quality']['rating'] == 'GOOD'])
        
        print(f"\nRating Distribution:")
        print(f"  EXCELLENT (80+): {excellent}")
        print(f"  VERY GOOD (70-79): {very_good}")
        print(f"  GOOD (60-69): {good}")
        print(f"  Others: {len(self.analyzed_stocks) - excellent - very_good - good}")
        
        self.top_20_stocks = self.analyzed_stocks[:min(20, len(self.analyzed_stocks))]
        
        print(f"\n✓ Selected TOP {len(self.top_20_stocks)} stocks for investment")
        print(f"{'='*80}\n")
        
        self.allocate_capital_top20()
    
    def allocate_capital_top20(self):
        """Allocate 100% capital across top 20 stocks"""
        try:
            if not self.top_20_stocks:
                print("⚠️  No stocks to allocate capital to.")
                return
            
            print(f"{'='*80}")
            print("CAPITAL ALLOCATION - TOP 20 STOCKS")
            print(f"{'='*80}\n")
            
            weights = []
            for stock in self.top_20_stocks:
                quality_score = stock['quality']['quality_score']
                cagr = stock['performance']['cagr']
                sharpe = stock['performance']['sharpe_ratio']
                
                base_weight = quality_score
                cagr_factor = min(cagr / 100, 0.5)
                sharpe_factor = min(sharpe / 5, 0.3)
                
                weight = base_weight * (1 + cagr_factor) * (1 + sharpe_factor)
                weights.append(weight)
            
            total_weight = sum(weights)
            normalized_weights = [w / total_weight for w in weights]
            
            total_allocated = 0
            
            for idx, stock in enumerate(self.top_20_stocks):
                current_price = stock['current_price']
                
                target_allocation = self.investment_capital * normalized_weights[idx]
                shares_to_buy = max(int(target_allocation / current_price), 1)
                actual_investment = shares_to_buy * current_price
                
                expected_return_30d = actual_investment * (stock['potential_gain_30d'] / 100)
                expected_return_90d = actual_investment * (stock['potential_gain_90d'] / 100)
                
                allocation = {
                    'allocation_percentage': float(normalized_weights[idx] * 100),
                    'investment_amount': float(actual_investment),
                    'shares_to_buy': int(shares_to_buy),
                    'expected_return_30d': float(expected_return_30d),
                    'expected_return_90d': float(expected_return_90d),
                    'exit_value_30d': float(actual_investment + expected_return_30d),
                    'exit_value_90d': float(actual_investment + expected_return_90d),
                    'roi_30d': float((expected_return_30d / actual_investment) * 100),
                    'roi_90d': float((expected_return_90d / actual_investment) * 100)
                }
                
                stock['allocation'] = allocation
                total_allocated += actual_investment
            
            remaining = self.investment_capital - total_allocated
            
            if remaining > 100:
                print(f"Distributing remaining ₹{remaining:,.2f} to top {min(5, len(self.top_20_stocks))} stocks...\n")
                
                top_n = min(5, len(self.top_20_stocks))
                for stock in self.top_20_stocks[:top_n]:
                    if remaining <= 0:
                        break
                    
                    current_price = stock['current_price']
                    additional_shares = int(remaining / (current_price * top_n))
                    
                    if additional_shares > 0:
                        additional_investment = additional_shares * current_price
                        
                        if additional_investment <= remaining:
                            stock['allocation']['shares_to_buy'] += additional_shares
                            stock['allocation']['investment_amount'] += additional_investment
                            
                            new_amount = stock['allocation']['investment_amount']
                            stock['allocation']['expected_return_30d'] = new_amount * (stock['potential_gain_30d'] / 100)
                            stock['allocation']['expected_return_90d'] = new_amount * (stock['potential_gain_90d'] / 100)
                            stock['allocation']['exit_value_30d'] = new_amount + stock['allocation']['expected_return_30d']
                            stock['allocation']['exit_value_90d'] = new_amount + stock['allocation']['expected_return_90d']
                            stock['allocation']['roi_30d'] = (stock['allocation']['expected_return_30d'] / new_amount) * 100
                            stock['allocation']['roi_90d'] = (stock['allocation']['expected_return_90d'] / new_amount) * 100
                            
                            total_allocated += additional_investment
                            remaining -= additional_investment
            
            final_remaining = self.investment_capital - total_allocated
            utilization = (total_allocated / self.investment_capital) * 100
            
            print(f"{'='*80}")
            print(f"ALLOCATION SUMMARY")
            print(f"{'='*80}")
            print(f"Total Capital: ₹{self.investment_capital:,.2f}")
            print(f"Amount Invested: ₹{total_allocated:,.2f}")
            print(f"Remaining: ₹{final_remaining:,.2f}")
            print(f"Capital Utilization: {utilization:.2f}%")
            print(f"Number of Stocks: {len(self.top_20_stocks)}")
            
            total_return_30d = sum(s['allocation']['expected_return_30d'] for s in self.top_20_stocks)
            total_return_90d = sum(s['allocation']['expected_return_90d'] for s in self.top_20_stocks)
            
            print(f"\nExpected Returns (30 days): ₹{total_return_30d:,.2f} ({(total_return_30d/total_allocated)*100:.2f}%)")
            print(f"Expected Returns (90 days): ₹{total_return_90d:,.2f} ({(total_return_90d/total_allocated)*100:.2f}%)")
            print(f"{'='*80}\n")
            
            print("TOP 20 STOCKS - INVESTMENT BREAKDOWN:")
            print("="*80)
            
            for i, stock in enumerate(self.top_20_stocks, 1):
                alloc = stock['allocation']
                quality = stock['quality']
                perf = stock['performance']
                
                print(f"\n{i}. {stock['name']} ({stock['symbol'].replace('.NS', '')})")
                print(f"   Sector: {stock['sector']} | Rating: {quality['rating']} | Score: {quality['quality_score']}/100")
                print(f"   Price: ₹{stock['current_price']:.2f} | 2Y Return: {perf['return_2y']:+.1f}% | CAGR: {perf['cagr']:.1f}%")
                print(f"   💰 INVEST: ₹{alloc['investment_amount']:,.0f} ({alloc['allocation_percentage']:.1f}%) - {alloc['shares_to_buy']} shares")
                print(f"   📈 30-Day Target: ₹{stock['target_30d']:.2f} | Expected: ₹{alloc['expected_return_30d']:,.0f} ({alloc['roi_30d']:.1f}%)")
                print(f"   📊 90-Day Target: ₹{stock['target_90d']:.2f} | Expected: ₹{alloc['expected_return_90d']:,.0f} ({alloc['roi_90d']:.1f}%)")
            
        except Exception as e:
            print(f"Error in allocation: {str(e)}")
            import traceback
            traceback.print_exc()
    
