        total_return_30d = sum(s['allocation']['expected_return_30d'] for s in analyzer.top_20_stocks)
        total_return_90d = sum(s['allocation']['expected_return_90d'] for s in analyzer.top_20_stocks)
        avg_cagr = sum(s['performance']['cagr'] for s in analyzer.top_20_stocks) / len(analyzer.top_20_stocks)
        
        print(f"\n{'='*80}")
